/**
 * Pure validation functions for notification preferences.
 *
 * These validators contain no side effects and no database calls.
 * They operate on a preferences object (or undefined for opt-out model).
 *
 * Each notification channel (email, SMS, webhook) has its own enable/disable
 * toggle. Category subscriptions apply across all channels.
 */

import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

/**
 * Determine whether a notification should be sent based on user preferences.
 *
 * Rules:
 * - If preferences is undefined, notifications are allowed (opt-out model).
 * - If the channel's enabled toggle is false, the notification is blocked.
 * - If the notification type is not in subscribedCategories, it is blocked.
 */
export function shouldSendNotification(
  preferences: UserNotificationPreferences | undefined,
  channel: NotificationChannel,
  notificationType: NotificationType,
): boolean {
  // No preferences = allow everything (opt-out model)
  if (!preferences) {
    return true;
  }

  // Check per-channel enabled toggle
  if (channel === 'email' && !preferences.emailEnabled) {
    return false;
  }
  if (channel === 'sms' && !preferences.smsEnabled) {
    return false;
  }
  if (channel === 'webhook' && !preferences.webhookEnabled) {
    return false;
  }

  // Check category subscription
  if (!preferences.subscribedCategories.includes(notificationType)) {
    return false;
  }

  return true;
}

/**
 * Repository for user notification preferences.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class UserPreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled: record['emailEnabled'] as boolean,
      emailFrequency: record['emailFrequency'] as EmailFrequency,
      smsEnabled: (record['smsEnabled'] as boolean) ?? true,
      webhookEnabled: (record['webhookEnabled'] as boolean) ?? true,
      subscribedCategories: JSON.parse(record['subscribedCategories'] as string) as NotificationType[],
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      smsEnabled: entity.smsEnabled,
      webhookEnabled: entity.webhookEnabled,
      subscribedCategories: JSON.stringify(entity.subscribedCategories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find notification preferences for a specific user.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((pref) => pref.userId === userId);
    return results[0];
  }
}

/**
 * Service for managing user notification preferences.
 *
 * Provides CRUD operations for notification preferences and a
 * method to check whether a specific notification should be sent
 * to a given user based on their settings.
 *
 * Depends on:
 * - UserPreferencesRepository — data access for preferences
 */

import type { UserPreferencesRepository } from '../repositories/user-preferences.repository.js';
import type {
  UserNotificationPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { getDefaultPreferences } from '../models/user-preferences.js';
import { shouldSendNotification as checkShouldSend } from '../validators/preferences.validator.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (useful for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepo: UserPreferencesRepository) {}

  /**
   * Get notification preferences for a user.
   * Returns undefined if no preferences have been set.
   */
  getPreferences(userId: string): UserNotificationPreferences | undefined {
    this.logger.debug(`Getting preferences for user: ${userId}`);
    return this.preferencesRepo.findByUserId(userId);
  }

  /**
   * Create notification preferences for a user.
   * Throws if the user already has preferences — use updatePreferences instead.
   */
  createPreferences(input: CreatePreferencesInput): UserNotificationPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    const existing = this.preferencesRepo.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const id = generatePreferencesId();
    const defaults = getDefaultPreferences(input.userId, id);

    const preferences: UserNotificationPreferences = {
      ...defaults,
      emailEnabled: input.emailEnabled ?? defaults.emailEnabled,
      emailFrequency: input.emailFrequency ?? defaults.emailFrequency,
      smsEnabled: input.smsEnabled ?? defaults.smsEnabled,
      webhookEnabled: input.webhookEnabled ?? defaults.webhookEnabled,
      subscribedCategories: input.subscribedCategories ?? defaults.subscribedCategories,
    };

    return this.preferencesRepo.save(preferences);
  }

  /**
   * Update notification preferences for a user.
   * Throws if no preferences exist for the user.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updated: Partial<UserNotificationPreferences> = { updatedAt: new Date() };

    if (input.emailEnabled !== undefined) {
      updated.emailEnabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updated.emailFrequency = input.emailFrequency;
    }
    if (input.smsEnabled !== undefined) {
      updated.smsEnabled = input.smsEnabled;
    }
    if (input.webhookEnabled !== undefined) {
      updated.webhookEnabled = input.webhookEnabled;
    }
    if (input.subscribedCategories !== undefined) {
      updated.subscribedCategories = input.subscribedCategories;
    }

    return this.preferencesRepo.update(existing.id, updated);
  }

  /**
   * Delete notification preferences for a user.
   * Returns true if preferences were found and deleted, false otherwise.
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);
    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      return false;
    }
    return this.preferencesRepo.delete(existing.id);
  }

  /**
   * Check whether a notification should be sent to a user based on
   * their preferences.
   *
   * Rules:
   * - If the user has no preferences, notifications are allowed (opt-out model).
   * - If the channel's enabled toggle is false, the notification is blocked.
   * - If the notification type is not in subscribedCategories, it is blocked.
   */
  shouldSendNotification(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepo.findByUserId(userId);
    const result = checkShouldSend(preferences, channel, notificationType);

    if (!result && preferences) {
      if (channel === 'email' && !preferences.emailEnabled) {
        this.logger.info(`Email notifications disabled for user: ${userId}`);
      } else if (channel === 'sms' && !preferences.smsEnabled) {
        this.logger.info(`SMS notifications disabled for user: ${userId}`);
      } else if (channel === 'webhook' && !preferences.webhookEnabled) {
        this.logger.info(`Webhook notifications disabled for user: ${userId}`);
      } else {
        this.logger.info(
          `User ${userId} not subscribed to ${notificationType}`,
        );
      }
    }

    return result;
  }
}

import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/preferences.validator.js';
import type { UserNotificationPreferences } from '../../src/models/user-preferences.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

function makePreferences(
  overrides: Partial<UserNotificationPreferences> = {},
): UserNotificationPreferences {
  return {
    id: 'pref-0001',
    userId: 'user-1',
    emailEnabled: true,
    emailFrequency: 'instant',
    smsEnabled: true,
    webhookEnabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('Preferences Validators', () => {
  describe('shouldSendNotification', () => {
    it('should allow notification when preferences is undefined (opt-out model)', () => {
      expect(shouldSendNotification(undefined, 'email', 'order_confirmation')).toBe(true);
    });

    it('should allow notification when all preferences are enabled', () => {
      const prefs = makePreferences();
      expect(shouldSendNotification(prefs, 'email', 'order_confirmation')).toBe(true);
    });

    it('should block email notification when emailEnabled is false', () => {
      const prefs = makePreferences({ emailEnabled: false });
      expect(shouldSendNotification(prefs, 'email', 'order_confirmation')).toBe(false);
    });

    it('should allow non-email channel even when emailEnabled is false', () => {
      const prefs = makePreferences({ emailEnabled: false });
      expect(shouldSendNotification(prefs, 'in-app', 'order_confirmation')).toBe(true);
    });

    it('should block notification when category is not subscribed', () => {
      const prefs = makePreferences({
        subscribedCategories: ['order_confirmation'],
      });
      expect(shouldSendNotification(prefs, 'email', 'order_status_update')).toBe(false);
    });

    it('should allow notification for subscribed category', () => {
      const prefs = makePreferences({
        subscribedCategories: ['order_confirmation'],
      });
      expect(shouldSendNotification(prefs, 'email', 'order_confirmation')).toBe(true);
    });

    it('should block when email disabled takes precedence over category', () => {
      const prefs = makePreferences({
        emailEnabled: false,
        subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
      });
      expect(shouldSendNotification(prefs, 'email', 'order_confirmation')).toBe(false);
    });

    it('should handle webhook channel with category check', () => {
      const prefs = makePreferences({
        subscribedCategories: ['user_welcome'],
      });
      expect(shouldSendNotification(prefs, 'webhook', 'user_welcome')).toBe(true);
      expect(shouldSendNotification(prefs, 'webhook', 'order_confirmation')).toBe(false);
    });

    // SMS channel tests
    it('should block SMS notification when smsEnabled is false', () => {
      const prefs = makePreferences({ smsEnabled: false });
      expect(shouldSendNotification(prefs, 'sms', 'order_confirmation')).toBe(false);
    });

    it('should allow SMS notification when smsEnabled is true', () => {
      const prefs = makePreferences();
      expect(shouldSendNotification(prefs, 'sms', 'order_confirmation')).toBe(true);
    });

    it('should not block SMS when emailEnabled is false', () => {
      const prefs = makePreferences({ emailEnabled: false });
      expect(shouldSendNotification(prefs, 'sms', 'order_confirmation')).toBe(true);
    });

    it('should block SMS when smsEnabled is false even if category is subscribed', () => {
      const prefs = makePreferences({
        smsEnabled: false,
        subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
      });
      expect(shouldSendNotification(prefs, 'sms', 'order_confirmation')).toBe(false);
    });

    // Webhook channel tests
    it('should block webhook notification when webhookEnabled is false', () => {
      const prefs = makePreferences({ webhookEnabled: false });
      expect(shouldSendNotification(prefs, 'webhook', 'order_confirmation')).toBe(false);
    });

    it('should allow webhook notification when webhookEnabled is true', () => {
      const prefs = makePreferences();
      expect(shouldSendNotification(prefs, 'webhook', 'order_confirmation')).toBe(true);
    });

    it('should not block webhook when email and sms are disabled', () => {
      const prefs = makePreferences({ emailEnabled: false, smsEnabled: false });
      expect(shouldSendNotification(prefs, 'webhook', 'order_confirmation')).toBe(true);
    });

    // Cross-channel independence
    it('should allow disabling each channel independently', () => {
      const prefs = makePreferences({
        emailEnabled: false,
        smsEnabled: false,
        webhookEnabled: true,
      });
      expect(shouldSendNotification(prefs, 'email', 'order_confirmation')).toBe(false);
      expect(shouldSendNotification(prefs, 'sms', 'order_confirmation')).toBe(false);
      expect(shouldSendNotification(prefs, 'webhook', 'order_confirmation')).toBe(true);
    });

    it('should apply category filter across all channels', () => {
      const prefs = makePreferences({
        subscribedCategories: ['order_confirmation'],
      });
      expect(shouldSendNotification(prefs, 'email', 'order_status_update')).toBe(false);
      expect(shouldSendNotification(prefs, 'sms', 'order_status_update')).toBe(false);
      expect(shouldSendNotification(prefs, 'webhook', 'order_status_update')).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: UserPreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new UserPreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('instant');
      expect(prefs.smsEnabled).toBe(true);
      expect(prefs.webhookEnabled).toBe(true);
      expect(prefs.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
      expect(prefs.id).toBe('pref-0001');
    });

    it('should create preferences with custom values', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        emailFrequency: 'daily',
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('daily');
      expect(prefs.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should create preferences with SMS and webhook disabled', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        smsEnabled: false,
        webhookEnabled: false,
      });

      expect(prefs.smsEnabled).toBe(false);
      expect(prefs.webhookEnabled).toBe(false);
      expect(prefs.emailEnabled).toBe(true); // default unchanged
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for existing user', () => {
      service.createPreferences({ userId: 'user-1', emailFrequency: 'weekly' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs?.emailFrequency).toBe('weekly');
    });

    it('should return undefined for user without preferences', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update emailEnabled', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailEnabled: false });
      expect(updated.emailEnabled).toBe(false);
      expect(updated.emailFrequency).toBe('instant'); // unchanged
    });

    it('should update emailFrequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailFrequency: 'daily' });
      expect(updated.emailFrequency).toBe('daily');
    });

    it('should update subscribedCategories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });
      expect(updated.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update smsEnabled', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { smsEnabled: false });
      expect(updated.smsEnabled).toBe(false);
      expect(updated.emailEnabled).toBe(true); // unchanged
      expect(updated.webhookEnabled).toBe(true); // unchanged
    });

    it('should update webhookEnabled', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { webhookEnabled: false });
      expect(updated.webhookEnabled).toBe(false);
      expect(updated.emailEnabled).toBe(true); // unchanged
      expect(updated.smsEnabled).toBe(true); // unchanged
    });

    it('should update multiple channel toggles at once', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        emailEnabled: false,
        smsEnabled: false,
        webhookEnabled: false,
      });
      expect(updated.emailEnabled).toBe(false);
      expect(updated.smsEnabled).toBe(false);
      expect(updated.webhookEnabled).toBe(false);
    });

    it('should throw if preferences do not exist', () => {
      expect(() => service.updatePreferences('user-1', { emailEnabled: false })).toThrow(
        'No preferences found for user: user-1',
      );
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false if preferences do not exist', () => {
      expect(service.deletePreferences('nonexistent')).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    it('should allow notifications when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should allow notifications when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should block notifications when email is disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'email', 'order_confirmation')).toBe(false);
    });

    it('should block notifications when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'email', 'order_status_update')).toBe(false);
    });

    it('should allow non-email channels even when email is disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      // in-app channel should not be affected by emailEnabled flag
      expect(service.shouldSendNotification('user-1', 'in-app', 'order_confirmation')).toBe(true);
    });

    it('should block non-email channels when category is unsubscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'in-app', 'order_status_update')).toBe(
        false,
      );
    });

    it('should block SMS notifications when smsEnabled is false', () => {
      service.createPreferences({ userId: 'user-1', smsEnabled: false });

      expect(service.shouldSendNotification('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should allow SMS notifications when smsEnabled is true', () => {
      service.createPreferences({ userId: 'user-1' });

